// Normalize the LLM's tool args into a uniform { command } shape.
// Mirrors postgres-named-queries 'Normalize Input' (Stage 113): the toolWorkflow
// node uses specifyInputSchema:false, so the LLM passes a single RAW STRING as the
// tool's arg (no JSON wrapping). With the trigger in passthrough mode that string
// arrives at $json.query. Try every observed shape so the Switch can read
// $json.command uniformly. Valid commands: deploy_status | recent_logs.
const items = $input.all();
const raw = (items[0] && items[0].json) || {};
const valid = ['deploy_status', 'recent_logs'];
const tryString = (s) => {
  if (typeof s !== 'string') return '';
  const t = s.trim();
  if (!t) return '';
  if (valid.indexOf(t) >= 0) return t;
  try { const p = JSON.parse(t); if (p && typeof p.command === 'string') return p.command; } catch (e) { /* ignore */ }
  return '';
};
let cmd = '';
if (typeof raw.command === 'string' && raw.command) {
  cmd = valid.indexOf(raw.command.trim()) >= 0 ? raw.command.trim() : tryString(raw.command);
} else if (typeof raw.query === 'string') {
  cmd = tryString(raw.query);
} else if (raw.query && typeof raw.query === 'object' && typeof raw.query.command === 'string') {
  cmd = raw.query.command;
} else if (raw.input && typeof raw.input.command === 'string') {
  cmd = raw.input.command;
} else if (typeof raw.arguments === 'string') {
  cmd = tryString(raw.arguments);
}
return [{ json: { command: cmd, _raw_input: raw } }];

// Pick the latest deployment id from the status response so the logs query can
// target it. Railway's deploymentLogs needs a deploymentId; deployments(first:5)
// returns newest-first, so edges[0].node.id is the latest. Read-only: on any
// shape we don't recognise, return an empty id and let the logs query surface a
// GraphQL error (Format Output reports ok:false) rather than throwing.
const resp = ($input.first() && $input.first().json) || {};
let id = '';
try {
  const edges = resp.data.project.deployments.edges || [];
  if (edges.length && edges[0].node) id = edges[0].node.id || '';
} catch (e) { id = ''; }
return [{ json: { deploymentId: id } }];

// Flatten whichever Railway branch ran into a uniform tool response.
// command comes from Normalize Input. Keep staticUrl / any URLs intact (links are
// allowed downstream — the router egress allow-list permits railway.app/.com).
// ok is false when the GraphQL response carried an errors array.
const normalized = $('Normalize Input').first().json || {};
const command = String(normalized.command || '');
const items = $input.all().map(i => i && i.json).filter(Boolean);
const first = items[0] || {};
const ok = !(first && first.errors);
let data = first;
try {
  if (command === 'deploy_status') {
    const dep = ((first.data || {}).project || {}).deployments;
    data = (dep && Array.isArray(dep.edges)) ? dep.edges.map(e => e.node) : first;
  } else if (command === 'recent_logs') {
    data = (first.data && first.data.deploymentLogs) ? first.data.deploymentLogs : first;
  }
} catch (e) { data = first; }
return [{ json: { ok: ok, command: command, data: data } }];
